// Construye un caso "sintético" compatible con CASES a partir del JSON de detalle.
export function buildGenericCase(id, det) {
  return {
    id,
    role: det.rolLabel || det.rol,
    pat: det.tecnica,
    gw: [],
    title: det.titulo,
    scTitle: det.titulo,
    scSub: `${det.rolLabel || det.rol} · ${det.tecnica} · madurez ${det.madurez}`,
    n: NEUTRAL_N,
    risk: det.risk || 'Riesgo no documentado.',
    hitl: {es: '¿Aprobar la acción sensible del agente?', en: 'Approve the agent sensitive action?'},
    caps: det.caps || ['', '', '', '', ''],
    comps: [],
    blocks: (det.blocks || []).map((html, i) => ({
      h: STAGE_HEADS[i],
      body: html,
      tabs: i === 1 ? (det.tabs2 || null) : null,
    })),
    generic: true,
  };
}

